INSERT INTO department (department_code, department_name, department_des, department_image) VALUES ('DEPT001', '内科', '内科是医院的重点科室之一，拥有多名高素质医护人员。科室设有心血管、呼吸、消化、内分泌等专业组，擅长诊治高血压、糖尿病、冠心病等常见病及疑难病症，致力于为患者提供全方位的内科诊疗服务。', 'img_DEPT001.png');
INSERT INTO department (department_code, department_name, department_des, department_image) VALUES ('DEPT002', '外科', '外科是医院的技术优势科室，医术精湛。开展各类普通外科、微创及腹腔镜手术，在甲状腺、乳腺及胃肠肿瘤手术方面具有丰富经验，年手术量稳步增长，为患者健康保驾护航。', 'img_DEPT002.png');
INSERT INTO department (department_code, department_name, department_des, department_image) VALUES ('DEPT003', '儿科', '儿科专注于儿童健康，环境温馨。设有新生儿、儿童呼吸、消化等专业组。擅长诊治儿科常见病、多发病，提供预防接种、儿童保健、生长发育咨询等一站式医疗服务，陪伴孩子健康成长。', 'img_DEPT003.png');
INSERT INTO department (department_code, department_name, department_des, department_image) VALUES ('DEPT004', '妇产科', '妇产科集医疗、保健、宣教于一体。开展产前检查、围产期保健、无痛分娩及各类妇产科手术。在妇科肿瘤诊治、不孕不育、绝经期综合征管理等方面处于前沿地位。', 'img_DEPT004.png');
INSERT INTO department (department_code, department_name, department_des, department_image) VALUES ('DEPT005', '眼科', '眼科配备国际先进的眼科检查及手术设备。擅长白内障手术、青光眼防治、准分子激光手术及各类眼底病诊治。科室致力于防盲治盲，为患者重塑光明。', 'img_DEPT005.png');
INSERT INTO department (department_code, department_name, department_des, department_image) VALUES ('DEPT006', '耳鼻喉科', '耳鼻喉科专业诊治耳、鼻、咽喉及头颈部疾病。在听力损失防治、慢性鼻炎鼻窦炎微创治疗、咽喉部良恶性肿瘤切除等方面具有丰富临床经验，设备精良，技术领先。', 'img_DEPT006.png');
INSERT INTO department (department_code, department_name, department_des, department_image) VALUES ('DEPT007', '口腔科', '口腔科开展牙体牙髓病修复、牙齿矫正、种植牙、牙周病治疗及口腔颌面外科手术。秉承微创、无痛理念，结合先进数字化技术，为患者提供专业的口腔健康管理。', 'img_DEPT007.png');
INSERT INTO department (department_code, department_name, department_des, department_image) VALUES ('DEPT008', '皮肤科', '皮肤科擅长各类皮炎、湿疹、痤疮、银屑病等常见病及性传播疾病的诊治。拥有先进的激光治疗平台及光疗设备，开展医学美容、激光祛斑等特色服务，呵护您的皮肤健康。', 'img_DEPT008.png');
INSERT INTO department (department_code, department_name, department_des, department_image) VALUES ('DEPT009', '骨科', '骨科在骨折治疗、人工关节置换、脊柱微创手术及运动损伤修复领域具有卓越优势。科室配备先进手术室系统，致力于让患者早日下床行走，恢复运动功能。', 'img_DEPT009.png');
INSERT INTO department (department_code, department_name, department_des, department_image) VALUES ('DEPT010', '神经内科', '神经内科专业诊治脑血管意外（中风）、癫痫、帕金森病、周围神经病等。设有卒中单元，开展溶栓、取栓治疗，拥有雄厚的科研与临床救治实力。', 'img_DEPT010.png');
INSERT INTO department (department_code, department_name, department_des, department_image) VALUES ('DEPT011', '心内科', '心内科是治疗心脏血管疾病的核心科室。擅长冠心病介入治疗、心律失常射频消融、心脏起搏器植入。配备24小时急诊绿色通道，全天候守护心脏安全。', 'img_DEPT011.png');
INSERT INTO department (department_code, department_name, department_des, department_image) VALUES ('DEPT012', '消化内科', '消化内科拥有先进的电子胃肠镜中心。擅长胃镜、肠镜下的各类微创手术，对慢性胃炎、胃癌早期筛查、炎症性肠病及肝胆胰疾病具有精深的临床见解。', 'img_DEPT012.png');
INSERT INTO department (department_code, department_name, department_des, department_image) VALUES ('DEPT013', '呼吸内科', '呼吸内科在支气管哮喘、慢阻肺、肺炎、肺结核及肺癌的规范化诊治方面积累了大量经验。科室开展支气管镜检查及无创辅助通气，专注心肺功能康复。', 'img_DEPT013.png');
INSERT INTO department (department_code, department_name, department_des, department_image) VALUES ('DEPT014', '肾内科', '肾内科设有标准化血液透析中心。擅长各类肾炎、肾病综合征、急慢性肾功能衰竭的诊治。技术力量扎实，为肾友提供安全、高效的血液净化与慢病管理方案。', 'img_DEPT014.png');
INSERT INTO department (department_code, department_name, department_des, department_image) VALUES ('DEPT015', '内分泌科', '内分泌科专注于糖尿病、甲状腺疾病、骨质疏松及垂体肾上腺疾病的诊治。开展糖尿病强化治疗与健康大讲堂，致力于代谢疾病的长期规范化管理。', 'img_DEPT015.png');
INSERT INTO department (department_code, department_name, department_des, department_image) VALUES ('DEPT016', '泌尿外科', '泌尿外科擅长肾脏/输尿管结石微创治疗、前列腺疾病及泌尿系统肿瘤手术。开展达芬奇机器人/腹腔镜等高精尖技术，在疑难复杂泌尿疾病治疗上享誉业界。', 'img_DEPT016.png');
INSERT INTO department (department_code, department_name, department_des, department_image) VALUES ('DEPT017', '普通外科', '普通外科主要负责甲状腺、乳腺、疝气、肝胆道疾病及胃肠等手术。科室倡导围手术期加速康复理念（ERAS），技术全面，微创水平居于地区前列。', 'img_DEPT017.png');
INSERT INTO department (department_code, department_name, department_des, department_image) VALUES ('DEPT018', '精神心理科', '精神心理科专业提供心理测评、心理咨询及精神疾病诊治。擅长抑郁症、焦虑症、失眠症及青少年行为障碍的疏导与治疗，为您构建健康的心灵驿站。', 'img_DEPT018.png');
INSERT INTO doctor (doctor_code, doctor_name, department_code, title, specialty, doctor_des, doctor_image) VALUES ('DOC_DEPT001_1', '张军', 'DEPT001', '副主任医师', '高血压防治', '张军副主任医师，从事内科临床工作13年，具备深厚的临床背景。他长期致力于高血压防治的诊疗，已成功治愈数千例相关患者。', 'doc_DOC_DEPT001_1.png');
